from itertools import combinations, product

def subsets(n,k):
    return list(combinations(range(n),k))
def val_plucker(vals,n,r):
    # vals dict tuple sorted->0/1
    for I in subsets(n,r-1):
        I=set(I)
        for J in subsets(n,r+1):
            J=set(J)
            terms=[]
            for i in J-I:
                A=tuple(sorted(I|{i}))
                B=tuple(sorted(J-{i}))
                terms.append(vals[A]+vals[B])
            if len(terms)<2: continue
            m=min(terms)
            if terms.count(m)<2:
                return False
    return True
def incidence(vals_p, vals_q,n,a,b,nested=False):
