            terms=[]
            for i in J-I:
                A=tuple(sorted(I|{i}))
                B=tuple(sorted(J-{i}))
                terms.append(vals_p[A]+vals_q[B])
            if len(terms)==0: continue
            m=min(terms)
            if terms.count(m)<2:
                return False
    return True

